insert into public.tools (slug, name, tagline, description, category_slugs, pricing, price_from, website, features, featured, rating, review_count) values
  ('chatgpt', 'ChatGPT', 'The conversational assistant that started it all.', 'ChatGPT is a general-purpose AI assistant for writing, coding, brainstorming, and answering questions. It supports custom GPTs, browsing, file uploads, and image generation in a single chat interface.', ARRAY['chatbots', 'productivity']::text[], 'freemium', '$20/mo', 'https://chat.openai.com', ARRAY['Custom GPTs for repeatable workflows', 'Web browsing and file analysis', 'Voice mode for hands-free conversations', 'Image generation built in']::text[], true, 4.7, 18240),
  ('claude', 'Claude', 'A thoughtful assistant built for long, nuanced work.', 'Claude is Anthropic''s assistant, tuned for careful reasoning, long documents, and coding. Projects and Artifacts make it easy to keep context organized across sessions.', ARRAY['chatbots', 'productivity', 'coding']::text[], 'freemium', '$20/mo', 'https://claude.ai', ARRAY['200K+ token context window', 'Projects to organize ongoing work', 'Artifacts for live document and code previews', 'Strong performance on coding tasks']::text[], true, 4.8, 9120),
  ('notion-ai', 'Notion AI', 'Your notes, docs, and wiki — now with AI built in.', 'Notion AI adds writing assistance, Q&A over your workspace, and autofill for databases directly inside the docs and notes your team already uses.', ARRAY['note-taking', 'writing', 'productivity']::text[], 'freemium', '$10/mo', 'https://notion.so', ARRAY['Ask questions across your whole workspace', 'AI autofill for database properties', 'Tone and length rewriting', 'Meeting notes and action-item extraction']::text[], true, 4.6, 7310),
  ('mem', 'Mem', 'A self-organizing notes app that surfaces what matters.', 'Mem uses AI to automatically connect related notes, summarize meetings, and resurface relevant context right when you need it, without manual folders or tags.', ARRAY['note-taking', 'productivity']::text[], 'freemium', '$10/mo', 'https://mem.ai', ARRAY['Automatic note linking', 'AI-generated daily summaries', 'Smart search across your second brain', 'Calendar-aware meeting notes']::text[], false, 4.3, 1120),
  ('reflect', 'Reflect', 'Fast networked notes with AI-assisted recall.', 'Reflect combines a backlink-based note graph with AI features for transcription, summarization, and question-answering over your personal knowledge base.', ARRAY['note-taking']::text[], 'paid', '$10/mo', 'https://reflect.app', ARRAY['Bi-directional linking', 'AI meeting transcription', 'Daily notes workflow', 'End-to-end encryption']::text[], false, 4.4, 640),
  ('jasper', 'Jasper', 'On-brand marketing copy at scale.', 'Jasper helps marketing teams generate blog posts, ad copy, and social content that stays consistent with brand voice, style guides, and past campaigns.', ARRAY['writing', 'marketing']::text[], 'paid', '$49/mo', 'https://jasper.ai', ARRAY['Brand voice training', 'Campaign-level content briefs', 'Team collaboration workflows', 'SEO-mode long-form articles']::text[], false, 4.4, 3980),
  ('copy-ai', 'Copy.ai', 'Turn a product idea into ad copy in seconds.', 'Copy.ai offers templated workflows for ads, emails, and product descriptions, plus a chat mode for freeform copywriting and go-to-market content.', ARRAY['writing', 'marketing']::text[], 'freemium', '$36/mo', 'https://copy.ai', ARRAY['90+ copywriting templates', 'Workflow automation for GTM teams', 'Brand voice and infobase', 'Chrome extension for on-page rewriting']::text[], false, 4.2, 2870),
  ('grammarly', 'Grammarly', 'Grammar, tone, and clarity checking everywhere you type.', 'Grammarly reviews writing in real time across the browser, desktop, and email, catching grammar issues while suggesting tone and clarity improvements.', ARRAY['writing']::text[], 'freemium', '$12/mo', 'https://grammarly.com', ARRAY['Real-time grammar and spelling checks', 'Tone detection and rewrite suggestions', 'Plagiarism detection', 'Works across browser, desktop, and mobile']::text[], false, 4.5, 15600),
  ('sudowrite', 'Sudowrite', 'An AI writing partner built for novelists.', 'Sudowrite is tuned specifically for fiction, offering brainstorming, scene expansion, and rewriting tools that understand narrative structure and character voice.', ARRAY['writing']::text[], 'paid', '$19/mo', 'https://sudowrite.com', ARRAY['Story bible for character and plot tracking', 'Scene expansion and description tools', 'Style-matched rewriting', 'Brainstorming for plot twists']::text[], false, 4.3, 890),
  ('github-copilot', 'GitHub Copilot', 'AI pair programmer inside your editor.', 'GitHub Copilot autocompletes code, explains functions, and now runs full coding agent sessions across supported IDEs, trained on public and licensed code.', ARRAY['coding']::text[], 'freemium', '$10/mo', 'https://github.com/features/copilot', ARRAY['Inline autocomplete in most major IDEs', 'Chat for explaining and refactoring code', 'Agent mode for multi-file changes', 'Pull request summaries']::text[], true, 4.5, 11200),
  ('cursor', 'Cursor', 'A code editor built around an AI pair programmer.', 'Cursor is a fork of VS Code with deep AI integration, letting you chat with your codebase, generate multi-file diffs, and apply AI edits with full project context.', ARRAY['coding']::text[], 'freemium', '$20/mo', 'https://cursor.com', ARRAY['Codebase-aware chat and edits', 'Multi-file diff generation', 'Tab-to-complete predictive edits', 'Built-in terminal agent']::text[], false, 4.7, 5240),
  ('codeium', 'Codeium', 'Free AI autocomplete for individual developers.', 'Codeium provides fast code completion, chat, and search across 70+ languages, with a generous free tier for individuals and enterprise options for teams.', ARRAY['coding']::text[], 'freemium', 'Free', 'https://codeium.com', ARRAY['Free unlimited autocomplete for individuals', 'In-IDE chat and search', 'Support for 70+ languages', 'Self-hosted enterprise option']::text[], false, 4.4, 2410),
  ('replit-ai', 'Replit AI', 'Build and deploy full apps from a browser tab.', 'Replit''s AI agent scaffolds, writes, and deploys full-stack applications directly in the browser, pairing a cloud IDE with hosting and databases.', ARRAY['coding']::text[], 'freemium', '$25/mo', 'https://replit.com', ARRAY['Agent mode builds full apps from a prompt', 'Instant cloud hosting and deploys', 'Built-in database and auth', 'Real-time collaborative editor']::text[], false, 4.2, 1830),
  ('midjourney', 'Midjourney', 'Painterly, high-fidelity AI image generation.', 'Midjourney generates highly stylized, artistic images from text prompts, widely used by designers and artists for concept art, moodboards, and illustration.', ARRAY['image-generation', 'design']::text[], 'paid', '$10/mo', 'https://midjourney.com', ARRAY['Distinctive, high-quality art styles', 'Image remix and style referencing', 'Upscaling and outpainting', 'Web-based generation interface']::text[], true, 4.6, 9860),
  ('dalle', 'DALL·E 3', 'Prompt-accurate image generation from OpenAI.', 'DALL·E 3 is tightly integrated with ChatGPT, translating natural-language prompts into images with strong prompt adherence and text rendering.', ARRAY['image-generation']::text[], 'paid', '$20/mo', 'https://openai.com/dall-e-3', ARRAY['Strong prompt adherence', 'In-chat iteration with ChatGPT', 'Readable in-image text rendering', 'Inpainting for targeted edits']::text[], false, 4.4, 6120),
  ('stable-diffusion', 'Stable Diffusion', 'Open-source image generation you can self-host.', 'Stable Diffusion is an open-weight image model that can run locally or in the cloud, with a large ecosystem of fine-tunes, plugins, and UI front-ends.', ARRAY['image-generation']::text[], 'open-source', 'Free', 'https://stability.ai', ARRAY['Fully open weights, self-hostable', 'Huge community model and plugin ecosystem', 'Fine-tunable on custom datasets', 'Runs on consumer GPUs']::text[], false, 4.3, 4390),
  ('adobe-firefly', 'Adobe Firefly', 'Generative AI trained for commercial-safe use.', 'Firefly is Adobe''s generative model family, embedded across Photoshop and Illustrator, trained on licensed content for commercially safer output.', ARRAY['image-generation', 'design']::text[], 'freemium', '$10/mo', 'https://firefly.adobe.com', ARRAY['Trained on licensed, commercially-safe content', 'Deep integration with Photoshop and Illustrator', 'Generative fill and expand', 'Text effects and vector recoloring']::text[], false, 4.3, 3210),
  ('leonardo-ai', 'Leonardo.Ai', 'Fine-tuned image models for game and product art.', 'Leonardo.Ai offers a library of fine-tuned models optimized for game assets, product shots, and concept art, with training tools for custom styles.', ARRAY['image-generation', 'design']::text[], 'freemium', '$12/mo', 'https://leonardo.ai', ARRAY['Library of style-specific fine-tuned models', 'Custom model training', 'Real-time canvas editing', 'Consistent character generation']::text[], false, 4.3, 1980),
  ('runway', 'Runway', 'Generative video editing for modern creators.', 'Runway combines text-to-video generation with a full suite of AI editing tools like green screen, inpainting, and motion tracking in one browser-based editor.', ARRAY['video']::text[], 'freemium', '$15/mo', 'https://runwayml.com', ARRAY['Text-to-video and image-to-video generation', 'AI green screen and object removal', 'Motion brush for directed animation', 'Browser-based editing timeline']::text[], true, 4.5, 4670),
  ('synthesia', 'Synthesia', 'Turn scripts into talking-avatar videos.', 'Synthesia generates studio-quality videos with AI avatars and voiceover from a script, popular for training, onboarding, and product explainer videos.', ARRAY['video']::text[], 'paid', '$29/mo', 'https://synthesia.io', ARRAY['140+ AI avatars', '130+ languages and voices', 'Script-to-video in minutes', 'Custom avatar creation']::text[], false, 4.4, 2540),
  ('descript', 'Descript', 'Edit video and podcasts by editing text.', 'Descript transcribes audio and video, then lets you edit the recording by editing the transcript, with AI tools for filler-word removal and voice cloning.', ARRAY['video', 'audio']::text[], 'freemium', '$16/mo', 'https://descript.com', ARRAY['Edit media by editing the transcript', 'Studio Sound noise cleanup', 'Filler-word and silence removal', 'Overdub voice cloning']::text[], false, 4.6, 3120),
  ('heygen', 'HeyGen', 'AI avatar videos for marketing and localization.', 'HeyGen creates avatar-based videos and instantly translates them into dozens of languages with lip-synced dubbing, aimed at marketing and sales teams.', ARRAY['video']::text[], 'freemium', '$24/mo', 'https://heygen.com', ARRAY['Realistic AI avatars', 'Instant multi-language dubbing with lip sync', 'Custom avatar cloning', 'API for programmatic video generation']::text[], false, 4.4, 1760),
  ('elevenlabs', 'ElevenLabs', 'The most natural-sounding AI voices available.', 'ElevenLabs generates lifelike speech in dozens of languages, with voice cloning, a large voice library, and APIs for narration, dubbing, and conversational agents.', ARRAY['audio']::text[], 'freemium', '$5/mo', 'https://elevenlabs.io', ARRAY['Highly natural multilingual voices', 'Instant voice cloning', 'Studio tools for long-form narration', 'Low-latency conversational voice API']::text[], true, 4.7, 5980),
  ('suno', 'Suno', 'Generate full songs from a text prompt.', 'Suno turns a short description or lyrics into a complete song, including vocals and instrumentation, in a wide range of genres and styles.', ARRAY['audio']::text[], 'freemium', '$10/mo', 'https://suno.com', ARRAY['Full song generation with vocals', 'Custom lyrics support', 'Wide range of genres and moods', 'Stem export for further mixing']::text[], false, 4.5, 3340),
  ('murf', 'Murf AI', 'Studio-quality voiceovers for presentations and video.', 'Murf provides a large library of AI voices with fine-grained pitch, emphasis, and pacing controls, aimed at e-learning, marketing, and corporate video.', ARRAY['audio']::text[], 'freemium', '$29/mo', 'https://murf.ai', ARRAY['120+ voices across 20+ languages', 'Fine-grained prosody controls', 'Voice changer for existing recordings', 'Team collaboration workspace']::text[], false, 4.3, 1420),
  ('otter', 'Otter.ai', 'Live meeting transcription and summaries.', 'Otter joins video calls to transcribe conversations in real time, then generates summaries and action items so teams can skip manual note-taking.', ARRAY['audio', 'productivity']::text[], 'freemium', '$10/mo', 'https://otter.ai', ARRAY['Real-time meeting transcription', 'Automatic summaries and action items', 'Integrates with Zoom, Meet, and Teams', 'Searchable transcript archive']::text[], false, 4.3, 4980),
  ('perplexity', 'Perplexity', 'An answer engine with cited sources.', 'Perplexity answers questions in natural language by searching the web and citing its sources, functioning as a research-first alternative to traditional search.', ARRAY['research', 'chatbots']::text[], 'freemium', '$20/mo', 'https://perplexity.ai', ARRAY['Cited, source-linked answers', 'Focus modes for academic and code search', 'Follow-up question threads', 'Pro Search for deeper multi-step research']::text[], true, 4.6, 6710),
  ('elicit', 'Elicit', 'AI research assistant for academic literature.', 'Elicit helps researchers find, summarize, and extract data from academic papers, automating steps of literature review that would otherwise take hours.', ARRAY['research']::text[], 'freemium', '$12/mo', 'https://elicit.com', ARRAY['Semantic search across academic papers', 'Automatic summarization of findings', 'Structured data extraction across papers', 'Systematic review workflows']::text[], false, 4.5, 980),
  ('consensus', 'Consensus', 'Search that answers questions using scientific studies.', 'Consensus searches peer-reviewed research to answer questions directly, surfacing consensus meters that show how much studies agree on a topic.', ARRAY['research']::text[], 'freemium', '$9/mo', 'https://consensus.app', ARRAY['Search grounded in peer-reviewed studies', 'Consensus meter showing study agreement', 'One-click study summaries', 'Citation export for reports']::text[], false, 4.4, 720),
  ('zapier-ai', 'Zapier AI', 'Describe an automation, get a working workflow.', 'Zapier''s AI features let you describe an automation in plain language and generate a multi-step workflow (Zap) connecting thousands of apps.', ARRAY['productivity']::text[], 'freemium', '$19/mo', 'https://zapier.com', ARRAY['Natural-language Zap creation', '7,000+ app integrations', 'AI-powered data formatting steps', 'Built-in AI chatbot builder']::text[], false, 4.5, 8340),
  ('motion', 'Motion', 'AI that plans your calendar and task list for you.', 'Motion automatically schedules tasks, meetings, and projects into your calendar based on priority and deadlines, replanning your day as things change.', ARRAY['productivity']::text[], 'paid', '$34/mo', 'https://usemotion.com', ARRAY['Automatic daily schedule planning', 'Project and task management', 'Dynamic replanning around meetings', 'Team workload balancing']::text[], false, 4.2, 1340),
  ('figma-ai', 'Figma AI', 'AI-assisted design, built into your existing workflow.', 'Figma''s AI features generate first-draft UI layouts, rename layers, remove backgrounds, and translate mockups directly inside the design tool teams already use.', ARRAY['design']::text[], 'freemium', '$12/mo', 'https://figma.com', ARRAY['Text-to-design first drafts', 'Automatic layer renaming and organization', 'Background removal and image editing', 'One-click design translation']::text[], false, 4.6, 5410),
  ('galileo-ai', 'Galileo AI', 'Generate editable UI designs from a text prompt.', 'Galileo AI turns short prompts into fully editable, high-fidelity UI designs, giving designers a fast starting point instead of a blank canvas.', ARRAY['design']::text[], 'paid', '$20/mo', 'https://usegalileo.ai', ARRAY['Prompt-to-UI design generation', 'Editable layers exported to design tools', 'Design system-aware components', 'Multiple style variations per prompt']::text[], false, 4.2, 560),
  ('uizard', 'Uizard', 'Turn sketches and screenshots into UI mockups.', 'Uizard converts hand-drawn sketches or screenshots of existing apps into editable UI designs and prototypes, aimed at fast early-stage product design.', ARRAY['design']::text[], 'freemium', '$12/mo', 'https://uizard.io', ARRAY['Sketch-to-design conversion', 'Screenshot-to-editable-mockup', 'Text-to-theme generation', 'Real-time team collaboration']::text[], false, 4.1, 640),
  ('adcreative-ai', 'AdCreative.ai', 'Generate conversion-focused ad creative in bulk.', 'AdCreative.ai generates ad banners, social creatives, and copy variations at scale, with scoring to predict which creative will perform best.', ARRAY['marketing']::text[], 'paid', '$39/mo', 'https://adcreative.ai', ARRAY['Bulk ad creative generation', 'Creative performance scoring', 'Text-to-ad copy variations', 'Direct integration with ad platforms']::text[], false, 4.1, 1980),
  ('intercom-fin', 'Fin by Intercom', 'AI customer support agent that resolves tickets end to end.', 'Fin is an AI customer service agent trained on your help center content, able to resolve support tickets autonomously and hand off to humans when needed.', ARRAY['chatbots', 'productivity']::text[], 'paid', '$0.99/resolution', 'https://intercom.com/fin', ARRAY['Autonomous ticket resolution', 'Trained on your help center and docs', 'Seamless handoff to human agents', 'Multi-language support']::text[], false, 4.4, 1120)
